import React, { useState, useRef } from "react";
import "./ConsultancyPage.css";

const ConsultancyPage = () => {
  const [search, setSearch] = useState("");
  const [showSuggestions, setShowSuggestions] = useState(false);
  const cardRefs = useRef({});

  const [consultants] = useState([
    { id: 1, name: "Dr. Ramesh Kumar", specialty: "Cardiologist", location: "Hyderabad" },
    { id: 2, name: "Dr. Priya Sharma", specialty: "Dermatologist", location: "Vijayawada" },
    { id: 3, name: "Dr. Anil Varma", specialty: "Orthopedic", location: "Visakhapatnam" },
    { id: 4, name: "Dr. Suma Devi", specialty: "Neurologist", location: "Guntur" },
    { id: 5, name: "Dr. Rajesh Rao", specialty: "General Physician", location: "Tirupati" },
  ]);

  const filteredConsultants = consultants.filter(
    (c) =>
      c.name.toLowerCase().includes(search.toLowerCase()) ||
      c.specialty.toLowerCase().includes(search.toLowerCase()) ||
      c.location.toLowerCase().includes(search.toLowerCase())
  );

  const suggestions = consultants.filter(
    (c) =>
      c.name.toLowerCase().includes(search.toLowerCase()) ||
      c.specialty.toLowerCase().includes(search.toLowerCase()) ||
      c.location.toLowerCase().includes(search.toLowerCase())
  );

  const handleSuggestionClick = (consultant) => {
    setSearch(consultant.name);
    setShowSuggestions(false);
    if (cardRefs.current[consultant.id]) {
      cardRefs.current[consultant.id].scrollIntoView({ behavior: "smooth", block: "center" });
    }
  };

  return (
    <div className="consultancy-container">
      <h2>Online Consultancy</h2>

      {/* 🔍 Search Section (same as BloodBank) */}
      <div className="search-section">
        <input
          type="text"
          placeholder="Search by doctor, specialty, or location..."
          value={search}
          onChange={(e) => {
            setSearch(e.target.value);
            setShowSuggestions(true);
          }}
          onBlur={() => setTimeout(() => setShowSuggestions(false), 150)}
          className="modern-search-input"
        />
        <button className="modern-search-btn">Search</button>

        {showSuggestions && search && (
          <ul className="modern-suggestion-box suggestions-list">
            {suggestions.length > 0 ? (
              suggestions.map((c, idx) => (
                <li
                  key={idx}
                  className="modern-suggestion-item"
                  onClick={() => handleSuggestionClick(c)}
                >
                  <strong>{c.name}</strong>
                  <span className="suggestion-type">
                    ({c.specialty} • {c.location})
                  </span>
                </li>
              ))
            ) : (
              <li className="modern-no-suggestion">No results found</li>
            )}
          </ul>
        )}
      </div>

      {/* 🩺 Consultant Cards */}
      <div className="consultancy-list">
        {filteredConsultants.length > 0 ? (
          filteredConsultants.map((c) => (
            <div
              key={c.id}
              ref={(el) => (cardRefs.current[c.id] = el)}
              className="consultancy-card"
            >
              <h3>{c.name}</h3>
              <p>{c.specialty}</p>
              <p>{c.location}</p>
            </div>
          ))
        ) : (
          <p className="no-results">No matching results found.</p>
        )}
      </div>
    </div>
  );
};

export default ConsultancyPage;
